6	interface ListOptions {
7	  status?: string;
8	  assignee?: string;
9	  tags?: string;
10	  parentId?: string;
11	}
12	
13	/**
14	 * Handler for the `trackgentic list` command.
15	 */
16	export async function listAction(options: ListOptions): Promise<void> {
17	  try {
18	    const tracker = new Tracker();
19	    const params: ListParams = {};
20	
21	    if (options.status !== undefined) {
22	      params.status = options.status as IssueStatus | "open";
23	    }
24	    if (options.assignee !== undefined) params.assignee = options.assignee;
25	    if (options.tags !== undefined) {
26	      params.tags = options.tags.split(",").map((t) => t.trim());
27	    }
28	    if (options.parentId !== undefined) {
29	      params.parentId = options.parentId === "null" ? null : options.parentId;
30	    }
31	
32	    const result = await tracker.list(params);
33	    writeStdout(result);
34	    process.exit(0);
35	  } catch (err) {
36	    if (err instanceof TrackgenticError) {
37	      writeStderr({ result: err.result, message: err.message });
38	      process.exit(err.exitCode);
39	    }
40	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
41	    process.exit(1);
42	  }
43	}
